#define INPUT_6_OUTPUT_SHIFT 7
#define CONV2D_15_OUTPUT_SHIFT 7
#define RE_LU_20_OUTPUT_SHIFT 7
#define MAX_POOLING2D_15_OUTPUT_SHIFT 7
#define CONV2D_16_OUTPUT_SHIFT 6
#define RE_LU_21_OUTPUT_SHIFT 6
#define MAX_POOLING2D_16_OUTPUT_SHIFT 6
#define CONV2D_17_OUTPUT_SHIFT 3
#define RE_LU_22_OUTPUT_SHIFT 3
#define MAX_POOLING2D_17_OUTPUT_SHIFT 3
#define FLATTEN_5_OUTPUT_SHIFT 3
#define DENSE_10_OUTPUT_SHIFT 0
#define RE_LU_23_OUTPUT_SHIFT 0
#define DENSE_11_OUTPUT_SHIFT 7

/* bias shift and output shift for each layer */
#define CONV2D_15_OUTPUT_RSHIFT (INPUT_6_OUTPUT_SHIFT+CONV2D_15_KERNEL_0_SHIFT-CONV2D_15_OUTPUT_SHIFT)
#define CONV2D_15_BIAS_LSHIFT   (INPUT_6_OUTPUT_SHIFT+CONV2D_15_KERNEL_0_SHIFT-CONV2D_15_BIAS_0_SHIFT)
#if CONV2D_15_OUTPUT_RSHIFT < 0
#error CONV2D_15_OUTPUT_RSHIFT must be bigger than 0
#endif
#if CONV2D_15_BIAS_LSHIFT < 0
#error CONV2D_15_BIAS_RSHIFT must be bigger than 0
#endif
#define CONV2D_16_OUTPUT_RSHIFT (MAX_POOLING2D_15_OUTPUT_SHIFT+CONV2D_16_KERNEL_0_SHIFT-CONV2D_16_OUTPUT_SHIFT)
#define CONV2D_16_BIAS_LSHIFT   (MAX_POOLING2D_15_OUTPUT_SHIFT+CONV2D_16_KERNEL_0_SHIFT-CONV2D_16_BIAS_0_SHIFT)
#if CONV2D_16_OUTPUT_RSHIFT < 0
#error CONV2D_16_OUTPUT_RSHIFT must be bigger than 0
#endif
#if CONV2D_16_BIAS_LSHIFT < 0
#error CONV2D_16_BIAS_RSHIFT must be bigger than 0
#endif
#define CONV2D_17_OUTPUT_RSHIFT (MAX_POOLING2D_16_OUTPUT_SHIFT+CONV2D_17_KERNEL_0_SHIFT-CONV2D_17_OUTPUT_SHIFT)
#define CONV2D_17_BIAS_LSHIFT   (MAX_POOLING2D_16_OUTPUT_SHIFT+CONV2D_17_KERNEL_0_SHIFT-CONV2D_17_BIAS_0_SHIFT)
#if CONV2D_17_OUTPUT_RSHIFT < 0
#error CONV2D_17_OUTPUT_RSHIFT must be bigger than 0
#endif
#if CONV2D_17_BIAS_LSHIFT < 0
#error CONV2D_17_BIAS_RSHIFT must be bigger than 0
#endif
#define DENSE_10_OUTPUT_RSHIFT (FLATTEN_5_OUTPUT_SHIFT+DENSE_10_KERNEL_0_SHIFT-DENSE_10_OUTPUT_SHIFT)
#define DENSE_10_BIAS_LSHIFT   (FLATTEN_5_OUTPUT_SHIFT+DENSE_10_KERNEL_0_SHIFT-DENSE_10_BIAS_0_SHIFT)
#if DENSE_10_OUTPUT_RSHIFT < 0
#error DENSE_10_OUTPUT_RSHIFT must be bigger than 0
#endif
#if DENSE_10_BIAS_LSHIFT < 0
#error DENSE_10_BIAS_RSHIFT must be bigger than 0
#endif
//#define DENSE_11_OUTPUT_RSHIFT (RE_LU_23_OUTPUT_SHIFT+DENSE_11_KERNEL_0_SHIFT-DENSE_11_OUTPUT_SHIFT)
//#define DENSE_11_BIAS_LSHIFT   (RE_LU_23_OUTPUT_SHIFT+DENSE_11_KERNEL_0_SHIFT-DENSE_11_BIAS_0_SHIFT)
//#if DENSE_11_OUTPUT_RSHIFT < 0
//#error DENSE_11_OUTPUT_RSHIFT must be bigger than 0
//#endif

#define DENSE_11_OUTPUT_RSHIFT 2
#define DENSE_11_BIAS_LSHIFT 0
#if DENSE_11_BIAS_LSHIFT < 0
#error DENSE_11_BIAS_RSHIFT must be bigger than 0
#endif

/* weights for each layer */
static const int8_t conv2d_15_weights[] = CONV2D_15_KERNEL_0;
static const nnom_weight_t conv2d_15_w = { (const void*)conv2d_15_weights, CONV2D_15_OUTPUT_RSHIFT};
static const int8_t conv2d_15_bias[] = CONV2D_15_BIAS_0;
static const nnom_bias_t conv2d_15_b = { (const void*)conv2d_15_bias, CONV2D_15_BIAS_LSHIFT};
static const int8_t conv2d_16_weights[] = CONV2D_16_KERNEL_0;
static const nnom_weight_t conv2d_16_w = { (const void*)conv2d_16_weights, CONV2D_16_OUTPUT_RSHIFT};
static const int8_t conv2d_16_bias[] = CONV2D_16_BIAS_0;
static const nnom_bias_t conv2d_16_b = { (const void*)conv2d_16_bias, CONV2D_16_BIAS_LSHIFT};
static const int8_t conv2d_17_weights[] = CONV2D_17_KERNEL_0;
static const nnom_weight_t conv2d_17_w = { (const void*)conv2d_17_weights, CONV2D_17_OUTPUT_RSHIFT};
static const int8_t conv2d_17_bias[] = CONV2D_17_BIAS_0;
static const nnom_bias_t conv2d_17_b = { (const void*)conv2d_17_bias, CONV2D_17_BIAS_LSHIFT};
static const int8_t dense_10_weights[] = DENSE_10_KERNEL_0;
static const nnom_weight_t dense_10_w = { (const void*)dense_10_weights, DENSE_10_OUTPUT_RSHIFT};
static const int8_t dense_10_bias[] = DENSE_10_BIAS_0;
static const nnom_bias_t dense_10_b = { (const void*)dense_10_bias, DENSE_10_BIAS_LSHIFT};
static const int8_t dense_11_weights[] = DENSE_11_KERNEL_0;
static const nnom_weight_t dense_11_w = { (const void*)dense_11_weights, DENSE_11_OUTPUT_RSHIFT};
static const int8_t dense_11_bias[] = DENSE_11_BIAS_0;
static const nnom_bias_t dense_11_b = { (const void*)dense_11_bias, DENSE_11_BIAS_LSHIFT};

/* nnom model */
static int8_t nnom_input_data[1024];
static int8_t nnom_output_data[7];
static nnom_model_t* nnom_model_create(void)
{
	static nnom_model_t model;
	nnom_layer_t* layer[15];

	new_model(&model);

	layer[0] = Input(shape(32, 32, 1), nnom_input_data);
	layer[1] = model.hook(Conv2D(8, kernel(3, 3), stride(1, 1), dilation(1, 1), PADDING_SAME, &conv2d_15_w, &conv2d_15_b), layer[0]);
	layer[2] = model.active(act_relu(), layer[1]);
	layer[3] = model.hook(MaxPool(kernel(2, 2), stride(2, 2), PADDING_VALID), layer[2]);
	layer[4] = model.hook(Conv2D(16, kernel(3, 3), stride(1, 1), dilation(1, 1), PADDING_SAME, &conv2d_16_w, &conv2d_16_b), layer[3]);
	layer[5] = model.active(act_relu(), layer[4]);
	layer[6] = model.hook(MaxPool(kernel(2, 2), stride(2, 2), PADDING_VALID), layer[5]);
	layer[7] = model.hook(Conv2D(32, kernel(3, 3), stride(1, 1), dilation(1, 1), PADDING_SAME, &conv2d_17_w, &conv2d_17_b), layer[6]);
	layer[8] = model.active(act_relu(), layer[7]);
	layer[9] = model.hook(MaxPool(kernel(2, 2), stride(2, 2), PADDING_VALID), layer[8]);
	layer[10] = model.hook(Dense(16, &dense_10_w, &dense_10_b), layer[9]);
	layer[11] = model.active(act_relu(), layer[10]);
	layer[12] = model.hook(Dense(7, &dense_11_w, &dense_11_b), layer[11]);
    //  layer[13] = model.hook(Output(shape(7,1,1), nnom_output_data), layer[12]);
    //  model_compile(&model, layer[0], layer[13]);

    layer[13] = model.hook(Softmax(), layer[12]);          // 新增 Softmax
    layer[14] = model.hook(Output(shape(7,1,1), nnom_output_data), layer[13]);

    model_compile(&model, layer[0], layer[14]);
	return &model;
}
